/**
 * Experiment Complexity Analyzer
 * Analyzes ForgeScript experiment code to detect complexity patterns and provide optimization suggestions
 */

import * as ts from 'typescript';
import { readFileSync } from 'fs';

export interface ExperimentMetrics {
  // Basic metrics
  totalLines: number;
  totalTrials: number;
  totalStimuli: number;
  totalResponses: number;
  totalTimelines: number;

  // Complexity metrics
  maxNestingDepth: number;
  chainLength: number;
  conditionalComplexity: number;
  loopComplexity: number;
  callbackComplexity: number;

  // Pattern detection
  builderPatterns: string[];
  antiPatterns: string[];

  // Performance impact
  estimatedMemoryUsage: number;
  estimatedRenderCost: number;
  timingPrecisionRisk: 'low' | 'medium' | 'high';

  // Suggestions
  optimizations: OptimizationSuggestion[];
  warnings: string[];
}

export interface OptimizationSuggestion {
  type: 'simplification' | 'performance' | 'readability' | 'maintainability';
  severity: 'info' | 'warning' | 'error';
  location: { line: number; column: number };
  message: string;
  suggestion: string;
  codeExample?: string;
}

export class ExperimentComplexityAnalyzer {
  private metrics: ExperimentMetrics = {
    totalLines: 0,
    totalTrials: 0,
    totalStimuli: 0,
    totalResponses: 0,
    totalTimelines: 0,
    maxNestingDepth: 0,
    chainLength: 0,
    conditionalComplexity: 0,
    loopComplexity: 0,
    callbackComplexity: 0,
    builderPatterns: [],
    antiPatterns: [],
    estimatedMemoryUsage: 0,
    estimatedRenderCost: 0,
    timingPrecisionRisk: 'low',
    optimizations: [],
    warnings: []
  };

  /**
   * Analyze experiment script for complexity
   */
  analyzeExperiment(code: string, fileName?: string): ExperimentMetrics {
    const sourceFile = ts.createSourceFile(
      fileName || 'experiment.ts',
      code,
      ts.ScriptTarget.Latest,
      true
    );

    this.metrics.totalLines = sourceFile.getLineAndCharacterOfPosition(sourceFile.end).line + 1;

    this.analyzeStructure(sourceFile);
    this.detectPatterns(sourceFile);
    this.calculateComplexity(sourceFile);
    this.estimatePerformanceImpact();
    this.generateOptimizations();

    return this.metrics;
  }

  /**
   * Analyze experiment from file
   */
  analyzeFile(filePath: string): ExperimentMetrics {
    const code = readFileSync(filePath, 'utf-8');
    return this.analyzeExperiment(code, filePath);
  }

  private analyzeStructure(sourceFile: ts.SourceFile) {
    const visit = (node: ts.Node, depth: number = 0) => {
      // Update max nesting depth
      this.metrics.maxNestingDepth = Math.max(this.metrics.maxNestingDepth, depth);

      // Count experiment components
      if (ts.isCallExpression(node)) {
        const expression = node.expression;
        if (ts.isPropertyAccessExpression(expression)) {
          const methodName = expression.name.text;

          // Count trials
          if (methodName === 'trial' || methodName === 'addTrial') {
            this.metrics.totalTrials++;
          }

          // Count stimuli
          if (methodName === 'stimulus' || methodName === 'addStimulus' || 
              methodName === 'text' || methodName === 'image' || methodName === 'video') {
            this.metrics.totalStimuli++;
          }

          // Count responses
          if (methodName === 'response' || methodName === 'keyboard' || 
              methodName === 'mouse' || methodName === 'touch') {
            this.metrics.totalResponses++;
          }

          // Count timelines
          if (methodName === 'timeline' || methodName === 'createTimeline') {
            this.metrics.totalTimelines++;
          }
        }
      }

      // Track conditionals
      if (ts.isIfStatement(node) || ts.isConditionalExpression(node)) {
        this.metrics.conditionalComplexity++;
      }

      // Track loops
      if (ts.isForStatement(node) || ts.isWhileStatement(node) || 
          ts.isForInStatement(node) || ts.isForOfStatement(node)) {
        this.metrics.loopComplexity++;
      }

      // Track callbacks
      if (ts.isArrowFunction(node) || ts.isFunctionExpression(node)) {
        this.metrics.callbackComplexity++;
      }

      ts.forEachChild(node, child => visit(child, depth + 1));
    };

    visit(sourceFile);
  }

  private detectPatterns(sourceFile: ts.SourceFile) {
    const chainedCalls: string[] = [];
    let currentChain: string[] = [];

    const visit = (node: ts.Node) => {
      // Detect builder chain patterns
      if (ts.isCallExpression(node) && ts.isPropertyAccessExpression(node.expression)) {
        const methodName = node.expression.name.text;
        currentChain.push(methodName);

        // Check if parent is also a call expression (chaining)
        if (!ts.isCallExpression(node.parent) || !ts.isPropertyAccessExpression(node.parent.expression)) {
          if (currentChain.length > 1) {
            chainedCalls.push(currentChain.join('.'));
            this.metrics.chainLength = Math.max(this.metrics.chainLength, currentChain.length);
          }
          currentChain = [];
        }
      }

      // Detect anti-patterns
      this.detectAntiPatterns(node);

      ts.forEachChild(node, visit);
    };

    visit(sourceFile);
    this.metrics.builderPatterns = [...new Set(chainedCalls)];
  }

  private detectAntiPatterns(node: ts.Node) {
    // Deep nesting in callbacks
    if (ts.isArrowFunction(node) || ts.isFunctionExpression(node)) {
      const depth = this.getCallbackDepth(node);
      if (depth > 3) {
        this.metrics.antiPatterns.push('Deep callback nesting');
        this.addOptimization({
          type: 'readability',
          severity: 'warning',
          location: this.getNodeLocation(node),
          message: 'Deep callback nesting detected',
          suggestion: 'Consider using async/await or breaking into smaller functions',
          codeExample: `// Instead of deeply nested callbacks:
experiment()
  .trial(() => {
    return stimulus(() => {
      return response(() => {
        // deep nesting
      });
    });
  });

// Use async/await:
experiment()
  .trial(async () => {
    await stimulus();
    await response();
  });`
        });
      }
    }

    // Synchronous heavy operations
    if (ts.isForStatement(node) || ts.isWhileStatement(node)) {
      const parent = node.parent;
      if (this.isInExperimentContext(parent)) {
        this.metrics.antiPatterns.push('Synchronous loop in experiment');
        this.addOptimization({
          type: 'performance',
          severity: 'error',
          location: this.getNodeLocation(node),
          message: 'Synchronous loop detected in experiment context',
          suggestion: 'Use async iteration or move computation outside of trial execution',
          codeExample: `// Avoid synchronous loops during trials:
// Bad:
.trial(() => {
  for (let i = 0; i < 10000; i++) {
    // heavy computation
  }
});

// Good:
const precomputed = computeHeavyData();
.trial(() => {
  usePrecomputedData(precomputed);
});`
        });
      }
    }

    // Repeated similar patterns
    if (ts.isCallExpression(node) && this.isSimilarToRecent(node)) {
      this.metrics.antiPatterns.push('Repeated similar code');
      this.addOptimization({
        type: 'maintainability',
        severity: 'info',
        location: this.getNodeLocation(node),
        message: 'Similar code pattern detected',
        suggestion: 'Consider extracting repeated patterns into reusable functions'
      });
    }
  }

  private calculateComplexity(sourceFile: ts.SourceFile) {
    // Cyclomatic complexity calculation
    let complexity = 1; // Base complexity

    const visit = (node: ts.Node) => {
      if (ts.isIfStatement(node) || ts.isConditionalExpression(node)) {
        complexity++;
      }
      if (ts.isForStatement(node) || ts.isWhileStatement(node) || 
          ts.isForInStatement(node) || ts.isForOfStatement(node)) {
        complexity++;
      }
      if (ts.isCaseClause(node)) {
        complexity++;
      }
      if (ts.isCatchClause(node)) {
        complexity++;
      }

      ts.forEachChild(node, visit);
    };

    visit(sourceFile);

    // Add warnings based on complexity
    if (complexity > 20) {
      this.metrics.warnings.push(`High cyclomatic complexity: ${complexity}`);
    }
  }

  private estimatePerformanceImpact() {
    // Estimate memory usage (rough approximation)
    const baseMemory = 50; // Base memory in KB
    const perTrial = 10;
    const perStimulus = 20;
    const perResponse = 5;

    this.metrics.estimatedMemoryUsage = 
      baseMemory + 
      (this.metrics.totalTrials * perTrial) +
      (this.metrics.totalStimuli * perStimulus) +
      (this.metrics.totalResponses * perResponse);

    // Estimate render cost
    const baseRender = 16; // Base render time in ms
    const perVisualStimulus = 8;
    const complexityPenalty = this.metrics.conditionalComplexity * 2;

    this.metrics.estimatedRenderCost = 
      baseRender + 
      (this.metrics.totalStimuli * perVisualStimulus) +
      complexityPenalty;

    // Assess timing precision risk
    if (this.metrics.loopComplexity > 5 || this.metrics.callbackComplexity > 20) {
      this.metrics.timingPrecisionRisk = 'high';
    } else if (this.metrics.loopComplexity > 2 || this.metrics.callbackComplexity > 10) {
      this.metrics.timingPrecisionRisk = 'medium';
    } else {
      this.metrics.timingPrecisionRisk = 'low';
    }

    // Add performance warnings
    if (this.metrics.estimatedRenderCost > 32) {
      this.metrics.warnings.push(
        `High render cost (${this.metrics.estimatedRenderCost}ms) may impact 60fps target`
      );
    }

    if (this.metrics.timingPrecisionRisk === 'high') {
      this.metrics.warnings.push(
        'High complexity may impact timing precision (<2ms target)'
      );
    }
  }

  private generateOptimizations() {
    // Chain length optimization
    if (this.metrics.chainLength > 10) {
      this.addOptimization({
        type: 'readability',
        severity: 'warning',
        location: { line: 0, column: 0 },
        message: `Long method chains detected (max: ${this.metrics.chainLength})`,
        suggestion: 'Break long chains into intermediate variables for better readability',
        codeExample: `// Instead of:
experiment()
  .trial()
  .stimulus()
  .duration(500)
  .position(0, 0)
  .size(100, 100)
  .color('red')
  .response()
  .keyboard(['space'])
  .timeout(2000)
  .build();

// Consider:
const stim = stimulus()
  .duration(500)
  .position(0, 0)
  .size(100, 100)
  .color('red');

const resp = response()
  .keyboard(['space'])
  .timeout(2000);

experiment()
  .trial()
  .add(stim)
  .add(resp)
  .build();`
      });
    }

    // Trial count optimization
    if (this.metrics.totalTrials > 100) {
      this.addOptimization({
        type: 'performance',
        severity: 'info',
        location: { line: 0, column: 0 },
        message: `Large number of trials (${this.metrics.totalTrials})`,
        suggestion: 'Consider using procedural generation or data-driven trial creation',
        codeExample: `// Instead of manually defining many trials:
// Use procedural generation:
const trialConfigs = generateTrialConfigs(100);
trialConfigs.forEach(config => {
  experiment.trial(createTrialFromConfig(config));
});`
      });
    }

    // JSON simplification
    if (this.metrics.totalLines > 200 && this.metrics.conditionalComplexity < 5) {
      this.addOptimization({
        type: 'simplification',
        severity: 'info',
        location: { line: 0, column: 0 },
        message: 'Consider using JSON declarative format for simple experiments',
        suggestion: 'This experiment might be simpler to express in JSON format',
        codeExample: `// Convert to JSON format:
{
  "version": "1.0",
  "experiment": {
    "trials": [
      {
        "stimulus": { "type": "text", "content": "+" },
        "response": { "type": "keyboard", "keys": ["space"] }
      }
    ]
  }
}`
      });
    }
  }

  private addOptimization(optimization: OptimizationSuggestion) {
    this.metrics.optimizations.push(optimization);
  }

  private getNodeLocation(node: ts.Node): { line: number; column: number } {
    const sourceFile = node.getSourceFile();
    const { line, character } = sourceFile.getLineAndCharacterOfPosition(node.getStart());
    return { line: line + 1, column: character + 1 };
  }

  private getCallbackDepth(node: ts.Node, depth: number = 0): number {
    if (!node.parent) return depth;
    if (ts.isArrowFunction(node.parent) || ts.isFunctionExpression(node.parent)) {
      return this.getCallbackDepth(node.parent, depth + 1);
    }
    return depth;
  }

  private isInExperimentContext(node: ts.Node | undefined): boolean {
    if (!node) return false;
    if (ts.isCallExpression(node) && ts.isPropertyAccessExpression(node.expression)) {
      const name = node.expression.name.text;
      if (['trial', 'stimulus', 'response', 'timeline'].includes(name)) {
        return true;
      }
    }
    return this.isInExperimentContext(node.parent);
  }

  private isSimilarToRecent(node: ts.CallExpression): boolean {
    // Simplified similarity check - in practice would be more sophisticated
    return false;
  }

  /**
   * Generate complexity report
   */
  generateReport(): string {
    const m = this.metrics;
    let report = '# Experiment Complexity Analysis\n\n';

    report += '## Structure Metrics\n';
    report += `- Total Lines: ${m.totalLines}\n`;
    report += `- Trials: ${m.totalTrials}\n`;
    report += `- Stimuli: ${m.totalStimuli}\n`;
    report += `- Responses: ${m.totalResponses}\n`;
    report += `- Timelines: ${m.totalTimelines}\n\n`;

    report += '## Complexity Metrics\n';
    report += `- Max Nesting Depth: ${m.maxNestingDepth}\n`;
    report += `- Max Chain Length: ${m.chainLength}\n`;
    report += `- Conditionals: ${m.conditionalComplexity}\n`;
    report += `- Loops: ${m.loopComplexity}\n`;
    report += `- Callbacks: ${m.callbackComplexity}\n\n`;

    report += '## Performance Impact\n';
    report += `- Estimated Memory: ${m.estimatedMemoryUsage}KB\n`;
    report += `- Estimated Render Cost: ${m.estimatedRenderCost}ms\n`;
    report += `- Timing Precision Risk: ${m.timingPrecisionRisk}\n\n`;

    if (m.warnings.length > 0) {
      report += '## Warnings\n';
      m.warnings.forEach(w => report += `- ⚠️  ${w}\n`);
      report += '\n';
    }

    if (m.antiPatterns.length > 0) {
      report += '## Anti-Patterns Detected\n';
      [...new Set(m.antiPatterns)].forEach(p => report += `- ${p}\n`);
      report += '\n';
    }

    if (m.optimizations.length > 0) {
      report += '## Optimization Suggestions\n';
      m.optimizations.forEach(opt => {
        const icon = opt.severity === 'error' ? '❌' : opt.severity === 'warning' ? '⚠️' : 'ℹ️';
        report += `\n### ${icon} ${opt.message}\n`;
        report += `**Location**: Line ${opt.location.line}, Column ${opt.location.column}\n`;
        report += `**Type**: ${opt.type}\n`;
        report += `**Suggestion**: ${opt.suggestion}\n`;
        if (opt.codeExample) {
          report += `\n\`\`\`typescript\n${opt.codeExample}\n\`\`\`\n`;
        }
      });
    }

    return report;
  }
}

