/**
 * Complexity Metrics Calculator
 * Advanced metrics calculation for ForgeScript API and experiments
 */

import { APIMetrics } from './APILinter.js';
import { ExperimentMetrics } from './ExperimentComplexityAnalyzer.js';

export interface ComplexityScore {
  overall: number;
  breakdown: {
    api: number;
    experiment: number;
    performance: number;
    maintainability: number;
    usability: number;
  };
  grade: 'A' | 'B' | 'C' | 'D' | 'F';
  trend: 'improving' | 'stable' | 'degrading';
  recommendations: string[];
}

export interface HistoricalMetrics {
  timestamp: Date;
  version: string;
  apiMetrics: APIMetrics;
  experimentMetrics?: ExperimentMetrics;
  score: ComplexityScore;
}

export class ComplexityMetricsCalculator {
  private historicalData: HistoricalMetrics[] = [];

  // Configurable weights for different aspects
  private weights = {
    api: {
      exports: 0.3,
      methods: 0.2,
      classes: 0.2,
      chainDepth: 0.15,
      deprecated: 0.15
    },
    experiment: {
      structure: 0.25,
      nesting: 0.2,
      patterns: 0.2,
      performance: 0.35
    },
    overall: {
      api: 0.4,
      experiment: 0.3,
      performance: 0.2,
      maintainability: 0.1
    }
  };

  // Thresholds for scoring
  private thresholds = {
    api: {
      exports: { excellent: 50, good: 80, fair: 100, poor: 150 },
      methods: { excellent: 100, good: 150, fair: 200, poor: 300 },
      classes: { excellent: 10, good: 20, fair: 30, poor: 50 },
      chainDepth: { excellent: 5, good: 8, fair: 12, poor: 20 }
    },
    experiment: {
      nesting: { excellent: 3, good: 5, fair: 8, poor: 12 },
      trials: { excellent: 50, good: 100, fair: 200, poor: 500 },
      renderCost: { excellent: 16, good: 32, fair: 48, poor: 64 }
    }
  };

  /**
   * Calculate complexity score from API metrics
   */
  calculateAPIComplexity(metrics: APIMetrics): number {
    const scores = {
      exports: this.normalizeScore(metrics.totalExports, this.thresholds.api.exports),
      methods: this.normalizeScore(metrics.publicMethods, this.thresholds.api.methods),
      classes: this.normalizeScore(metrics.publicClasses, this.thresholds.api.classes),
      chainDepth: this.normalizeScore(metrics.builderMethods, this.thresholds.api.chainDepth),
      deprecated: metrics.deprecatedAPIs > 0 ? (100 - metrics.deprecatedAPIs * 5) : 100
    };

    return this.weightedAverage(scores, this.weights.api);
  }

  /**
   * Calculate complexity score from experiment metrics
   */
  calculateExperimentComplexity(metrics: ExperimentMetrics): number {
    const structureScore = this.calculateStructureScore(metrics);
    const nestingScore = this.normalizeScore(metrics.maxNestingDepth, this.thresholds.experiment.nesting);
    const patternScore = this.calculatePatternScore(metrics);
    const performanceScore = this.calculatePerformanceScore(metrics);

    const scores = {
      structure: structureScore,
      nesting: nestingScore,
      patterns: patternScore,
      performance: performanceScore
    };

    return this.weightedAverage(scores, this.weights.experiment);
  }

  /**
   * Calculate overall complexity score
   */
  calculateOverallScore(
    apiMetrics: APIMetrics,
    experimentMetrics?: ExperimentMetrics,
    historicalData?: HistoricalMetrics[]
  ): ComplexityScore {
    if (historicalData) {
      this.historicalData = historicalData;
    }

    const apiScore = this.calculateAPIComplexity(apiMetrics);
    const experimentScore = experimentMetrics 
      ? this.calculateExperimentComplexity(experimentMetrics)
      : 100; // Perfect score if no experiment to analyze

    const performanceScore = this.calculatePerformanceImpact(apiMetrics, experimentMetrics);
    const maintainabilityScore = this.calculateMaintainability(apiMetrics, experimentMetrics);
    const usabilityScore = this.calculateUsability(apiMetrics);

    const breakdown = {
      api: apiScore,
      experiment: experimentScore,
      performance: performanceScore,
      maintainability: maintainabilityScore,
      usability: usabilityScore
    };

    const overall = this.weightedAverage(breakdown, this.weights.overall);
    const grade = this.scoreToGrade(overall);
    const trend = this.calculateTrend(overall);
    const recommendations = this.generateRecommendations(breakdown, apiMetrics, experimentMetrics);

    return {
      overall,
      breakdown,
      grade,
      trend,
      recommendations
    };
  }

  private calculateStructureScore(metrics: ExperimentMetrics): number {
    const trialScore = this.normalizeScore(metrics.totalTrials, this.thresholds.experiment.trials);
    const ratios = {
      stimuliPerTrial: metrics.totalTrials > 0 ? metrics.totalStimuli / metrics.totalTrials : 1,
      responsesPerTrial: metrics.totalTrials > 0 ? metrics.totalResponses / metrics.totalTrials : 1
    };

    // Ideal ratios
    const idealStimuliPerTrial = 2;
    const idealResponsesPerTrial = 1;

    const stimuliRatioScore = 100 - Math.abs(ratios.stimuliPerTrial - idealStimuliPerTrial) * 20;
    const responseRatioScore = 100 - Math.abs(ratios.responsesPerTrial - idealResponsesPerTrial) * 30;

    return (trialScore + stimuliRatioScore + responseRatioScore) / 3;
  }

  private calculatePatternScore(metrics: ExperimentMetrics): number {
    let score = 100;

    // Penalize anti-patterns
    score -= metrics.antiPatterns.length * 10;

    // Penalize very long chains
    if (metrics.chainLength > 15) score -= 20;
    else if (metrics.chainLength > 10) score -= 10;

    // Penalize excessive callbacks
    if (metrics.callbackComplexity > 20) score -= 15;

    return Math.max(0, score);
  }

  private calculatePerformanceScore(metrics: ExperimentMetrics): number {
    const renderScore = this.normalizeScore(
      metrics.estimatedRenderCost,
      this.thresholds.experiment.renderCost
    );

    const timingScore = {
      'low': 100,
      'medium': 70,
      'high': 40
    }[metrics.timingPrecisionRisk];

    const memoryScore = 100 - (metrics.estimatedMemoryUsage / 10); // Lose 1 point per 10KB

    return (renderScore + timingScore + Math.max(0, memoryScore)) / 3;
  }

  private calculatePerformanceImpact(
    apiMetrics: APIMetrics,
    experimentMetrics?: ExperimentMetrics
  ): number {
    let score = 100;

    // API performance impact
    if (apiMetrics.totalExports > 100) score -= 10;
    if (apiMetrics.publicMethods > 200) score -= 10;

    // Experiment performance impact
    if (experimentMetrics) {
      if (experimentMetrics.timingPrecisionRisk === 'high') score -= 30;
      else if (experimentMetrics.timingPrecisionRisk === 'medium') score -= 15;

      if (experimentMetrics.estimatedRenderCost > 48) score -= 20;
      else if (experimentMetrics.estimatedRenderCost > 32) score -= 10;
    }

    return Math.max(0, score);
  }

  private calculateMaintainability(
    apiMetrics: APIMetrics,
    experimentMetrics?: ExperimentMetrics
  ): number {
    let score = 100;

    // API maintainability
    score -= apiMetrics.deprecatedAPIs * 5;
    score -= apiMetrics.warnings.length * 3;

    // Experiment maintainability
    if (experimentMetrics) {
      score -= experimentMetrics.antiPatterns.length * 5;
      if (experimentMetrics.maxNestingDepth > 8) score -= 15;
      if (experimentMetrics.conditionalComplexity > 20) score -= 10;
    }

    return Math.max(0, score);
  }

  private calculateUsability(apiMetrics: APIMetrics): number {
    let score = 100;

    // Penalize too many options
    if (apiMetrics.totalExports > 80) {
      score -= (apiMetrics.totalExports - 80) * 0.5;
    }

    // Penalize inconsistent patterns
    if (apiMetrics.duplicatePatterns.length > 0) {
      score -= apiMetrics.duplicatePatterns.length * 10;
    }

    // Reward good practices
    if (apiMetrics.deprecatedAPIs === 0) score += 5;
    if (apiMetrics.recommendations.length === 0) score += 5;

    return Math.min(100, Math.max(0, score));
  }

  private calculateTrend(currentScore: number): 'improving' | 'stable' | 'degrading' {
    if (this.historicalData.length < 2) return 'stable';

    const recentScores = this.historicalData
      .slice(-5)
      .map(h => h.score.overall);

    const avgRecent = recentScores.reduce((a, b) => a + b, 0) / recentScores.length;

    if (currentScore > avgRecent + 5) return 'improving';
    if (currentScore < avgRecent - 5) return 'degrading';
    return 'stable';
  }

  private generateRecommendations(
    breakdown: ComplexityScore['breakdown'],
    apiMetrics: APIMetrics,
    experimentMetrics?: ExperimentMetrics
  ): string[] {
    const recommendations: string[] = [];

    // API recommendations
    if (breakdown.api < 70) {
      if (apiMetrics.totalExports > 100) {
        recommendations.push('Consider splitting API into core and advanced modules');
      }
      if (apiMetrics.builderMethods > 50) {
        recommendations.push('Simplify builder API - consider configuration objects');
      }
    }

    // Experiment recommendations
    if (experimentMetrics && breakdown.experiment < 70) {
      if (experimentMetrics.maxNestingDepth > 8) {
        recommendations.push('Reduce nesting depth - extract complex logic into functions');
      }
      if (experimentMetrics.antiPatterns.length > 3) {
        recommendations.push('Address detected anti-patterns to improve code quality');
      }
    }

    // Performance recommendations
    if (breakdown.performance < 70) {
      recommendations.push('Performance optimization needed - review timing-critical code');
    }

    // Maintainability recommendations
    if (breakdown.maintainability < 70) {
      recommendations.push('Improve code maintainability - reduce complexity and add documentation');
    }

    return recommendations;
  }

  private normalizeScore(
    value: number,
    thresholds: { excellent: number; good: number; fair: number; poor: number }
  ): number {
    if (value <= thresholds.excellent) return 100;
    if (value <= thresholds.good) return 80;
    if (value <= thresholds.fair) return 60;
    if (value <= thresholds.poor) return 40;
    return 20;
  }

  private weightedAverage(
    scores: Record<string, number>,
    weights: Record<string, number>
  ): number {
    let totalWeight = 0;
    let weightedSum = 0;

    for (const key in scores) {
      if (key in weights) {
        weightedSum += scores[key] * weights[key];
        totalWeight += weights[key];
      }
    }

    return totalWeight > 0 ? weightedSum / totalWeight : 0;
  }

  private scoreToGrade(score: number): 'A' | 'B' | 'C' | 'D' | 'F' {
    if (score >= 90) return 'A';
    if (score >= 80) return 'B';
    if (score >= 70) return 'C';
    if (score >= 60) return 'D';
    return 'F';
  }

  /**
   * Generate visual complexity report
   */
  generateVisualReport(score: ComplexityScore): string {
    const { overall, breakdown, grade, trend } = score;

    let report = '📊 Complexity Score Report\n';
    report += '═'.repeat(50) + '\n\n';

    // Overall score with visual bar
    report += `Overall Score: ${overall.toFixed(1)}/100 [${this.generateBar(overall)}] Grade: ${grade}\n`;
    report += `Trend: ${this.getTrendIcon(trend)} ${trend}\n\n`;

    // Breakdown with visual bars
    report += 'Breakdown:\n';
    report += `├─ API:           ${breakdown.api.toFixed(1)} [${this.generateBar(breakdown.api)}]\n`;
    report += `├─ Experiment:    ${breakdown.experiment.toFixed(1)} [${this.generateBar(breakdown.experiment)}]\n`;
    report += `├─ Performance:   ${breakdown.performance.toFixed(1)} [${this.generateBar(breakdown.performance)}]\n`;
    report += `├─ Maintainability: ${breakdown.maintainability.toFixed(1)} [${this.generateBar(breakdown.maintainability)}]\n`;
    report += `└─ Usability:     ${breakdown.usability.toFixed(1)} [${this.generateBar(breakdown.usability)}]\n\n`;

    // Recommendations
    if (score.recommendations.length > 0) {
      report += 'Recommendations:\n';
      score.recommendations.forEach(rec => {
        report += `• ${rec}\n`;
      });
    }

    return report;
  }

  private generateBar(score: number, width: number = 20): string {
    const filled = Math.round((score / 100) * width);
    const empty = width - filled;
    return '█'.repeat(filled) + '░'.repeat(empty);
  }

  private getTrendIcon(trend: 'improving' | 'stable' | 'degrading'): string {
    switch (trend) {
      case 'improving': return '📈';
      case 'stable': return '➡️';
      case 'degrading': return '📉';
    }
  }
}

