    repetitiveCode: {
      detect: (metrics: ExperimentMetrics) => metrics.antiPatterns.includes('Repeated similar code'),
      suggest: () => this.createRepetitiveCodeSuggestion()
    },

    syncLoops: {
      detect: (metrics: ExperimentMetrics) => metrics.antiPatterns.includes('Synchronous loop in experiment'),
      suggest: () => this.createSyncLoopSuggestion()
    },

    tooManyExports: {
      detect: (metrics: APIMetrics) => metrics.totalExports > 100,
      suggest: () => this.createModularizationSuggestion()
    },

    complexBuilder: {
      detect: (metrics: APIMetrics) => metrics.builderMethods > 50,
      suggest: () => this.createBuilderSimplificationSuggestion()
    }
  };

  /**
   * Analyze code and generate optimization suggestions
   */
  analyze(context: OptimizationContext): OptimizationSuggestion[] {
    this.suggestions = [];

    // Check experiment patterns
    if (context.experimentMetrics) {
      this.analyzeExperimentPatterns(context.experimentMetrics);
      this.analyzePerformanceIssues(context.experimentMetrics);
      this.suggestSimplifications(context.experimentMetrics);
    }

    // Check API patterns
    if (context.apiMetrics) {
      this.analyzeAPIPatterns(context.apiMetrics);
    }

    // Sort by priority
    this.suggestions.sort((a, b) => b.priority - a.priority);

    return this.suggestions;
  }

  private analyzeExperimentPatterns(metrics: ExperimentMetrics) {
    // Check each pattern
    Object.values(this.patterns).forEach(pattern => {
      if ('detect' in pattern && pattern.detect(metrics)) {
        const suggestion = pattern.suggest();
        if (suggestion) {
          this.suggestions.push(suggestion);
        }
      }
    });

    // Additional experiment-specific suggestions
    if (metrics.totalTrials > 100) {
      this.suggestions.push(this.createProceduralizationSuggestion(metrics.totalTrials));
    }

    if (metrics.conditionalComplexity > 20) {
      this.suggestions.push(this.createConditionalSimplificationSuggestion());
    }
  }

  private analyzePerformanceIssues(metrics: ExperimentMetrics) {
    if (metrics.timingPrecisionRisk === 'high') {
      this.suggestions.push({
        id: 'perf-timing-risk',
        type: 'performance',
        impact: 'high',
        effort: 'medium',
        priority: 9,
        title: 'High timing precision risk detected',
        description: 'Complex operations may interfere with 2ms timing precision target',
        rationale: 'ForgeScript requires <2ms timing precision for valid research data',
        before: `experiment()
  .trial(() => {
    // Complex synchronous operations
    const result = heavyComputation();
    return stimulus.text(result);
  })`,
        after: `// Pre-compute heavy operations
const precomputed = heavyComputation();

experiment()
  .trial(() => {
    return stimulus.text(precomputed);
  })`,
        automatable: false,
        relatedDocs: ['timing-precision.md', 'performance-guide.md']
      });
    }

    if (metrics.estimatedRenderCost > 32) {
      this.suggestions.push({
        id: 'perf-render-cost',
        type: 'performance',
        impact: 'medium',
        effort: 'medium',
        priority: 7,
        title: 'High render cost may impact frame rate',
        description: `Estimated render cost (${metrics.estimatedRenderCost}ms) exceeds 60fps budget`,
        rationale: 'Maintaining 60fps ensures smooth visual presentation',
        before: `// Many complex visual stimuli
experiment()
  .stimulus.image('img1.png').size(1000, 1000)
  .stimulus.image('img2.png').size(1000, 1000)
  .stimulus.image('img3.png').size(1000, 1000)`,
        after: `// Optimize images and use sprite sheets
const sprites = await loadSpriteSheet('optimized-sprites.png');

experiment()
  .stimulus.sprite(sprites, 'img1')
  .stimulus.sprite(sprites, 'img2')
  .stimulus.sprite(sprites, 'img3')`,
        automatable: false,
        relatedDocs: ['performance-guide.md', 'sprite-optimization.md']
      });
    }
  }

  private analyzeAPIPatterns(metrics: APIMetrics) {
    // Check API-specific patterns
    if (metrics.totalExports > 100) {
      const suggestion = this.patterns.tooManyExports.suggest();
      if (suggestion) this.suggestions.push(suggestion);
    }

    if (metrics.builderMethods > 50) {
      const suggestion = this.patterns.complexBuilder.suggest();
      if (suggestion) this.suggestions.push(suggestion);
    }

    if (metrics.deprecatedAPIs > 5) {
      this.suggestions.push(this.createDeprecationCleanupSuggestion(metrics.deprecatedAPIs));
    }
  }

  private suggestSimplifications(metrics: ExperimentMetrics) {
    // Suggest JSON format for simple experiments
    if (metrics.conditionalComplexity < 5 && metrics.callbackComplexity < 10) {
      this.suggestions.push({
        id: 'simplify-to-json',
        type: 'simplification',
        impact: 'medium',
        effort: 'low',
        priority: 6,
        title: 'Consider JSON declarative format',
        description: 'This experiment is simple enough to express in JSON format',
        rationale: 'JSON format is easier to read, modify, and share for simple experiments',
        before: `const exp = experiment('Simple RT')
  .trial()
    .stimulus.text('Press SPACE when you see X')
    .duration(2000)
  .trial()
    .stimulus.text('X')
    .response.keyboard(['space'])
    .timeout(5000)
  .build();`,
        after: `{
  "version": "1.0",
  "experiment": {
    "name": "Simple RT",
    "trials": [
      {
        "stimulus": {
          "type": "text",
          "content": "Press SPACE when you see X",
          "duration": 2000
        }
      },
      {
        "stimulus": {
          "type": "text",
          "content": "X"
        },
        "response": {
          "type": "keyboard",
          "keys": ["space"],
          "timeout": 5000
        }
      }
    ]
  }
}`,
        automatable: true,
        relatedDocs: ['json-format.md', 'experiment-formats.md']
      });
    }
  }

  // Specific suggestion creators
  private createDeepNestingSuggestion(): OptimizationSuggestion {
    return {
      id: 'refactor-deep-nesting',
      type: 'refactor',
      impact: 'high',
      effort: 'medium',
      priority: 8,
      title: 'Reduce deep nesting for better readability',
      description: 'Deep nesting makes code hard to read and maintain',
      rationale: 'Flatter code structure improves readability and reduces cognitive load',
      before: `experiment()
  .trial(() => {
    stimulus(() => {
      if (condition) {
        response(() => {
          if (anotherCondition) {
            // deeply nested logic
          }
        });
      }
    });
  });`,
      after: `// Extract nested logic into functions
const createStimulus = () => stimulus();
const createResponse = () => response();

experiment()
  .trial(async () => {
    const stim = await createStimulus();
    if (condition) {
      const resp = await createResponse();
      handleResponse(resp);
    }
  });`,
      automatable: false,
      relatedDocs: ['code-style.md', 'best-practices.md']
    };
  }

  private createLongChainSuggestion(): OptimizationSuggestion {
    return {
      id: 'refactor-long-chains',
      type: 'refactor',
      impact: 'medium',
      effort: 'low',
      priority: 6,
      title: 'Break long method chains for clarity',
      description: 'Long chains are hard to debug and understand',
      rationale: 'Intermediate variables make code more debuggable and clear',
      before: `experiment()
  .name('Complex Task')
  .participant(getParticipant())
  .trial()
  .stimulus.text('Hello')
  .position(100, 100)
  .size(200, 50)
  .color('red')
  .duration(1000)
  .response.keyboard(['y', 'n'])
  .timeout(5000)
  .onResponse(handleResponse)
  .build();`,
      after: `// Break into logical groups
const exp = experiment()
  .name('Complex Task')
  .participant(getParticipant());

const textStim = stimulus.text('Hello')
  .position(100, 100)
  .size(200, 50)
  .color('red')
  .duration(1000);

const keyResponse = response.keyboard(['y', 'n'])
  .timeout(5000)
  .onResponse(handleResponse);

exp.trial()
  .add(textStim)
  .add(keyResponse)
  .build();`,
      automatable: true,
      relatedDocs: ['fluent-api.md', 'code-style.md']
    };
  }

  private createRepetitiveCodeSuggestion(): OptimizationSuggestion {
    return {
      id: 'refactor-repetitive',
      type: 'refactor',
      impact: 'medium',
      effort: 'medium',
      priority: 5,
      title: 'Extract repetitive patterns into reusable functions',
      description: 'Repeated code patterns should be abstracted',
      rationale: 'DRY principle reduces maintenance burden and bugs',
      before: `experiment()
  .trial()
    .stimulus.text('Trial 1')
    .duration(1000)
    .response.keyboard(['space'])
  .trial()
    .stimulus.text('Trial 2')
    .duration(1000)
    .response.keyboard(['space'])
  .trial()
    .stimulus.text('Trial 3')
    .duration(1000)
    .response.keyboard(['space'])`,
      after: `// Create reusable trial factory
const createStandardTrial = (text: string) => 
  trial()
    .stimulus.text(text)
    .duration(1000)
    .response.keyboard(['space']);

experiment()
  .add(createStandardTrial('Trial 1'))
  .add(createStandardTrial('Trial 2'))
  .add(createStandardTrial('Trial 3'))`,
      automatable: true,
      relatedDocs: ['patterns.md', 'reusability.md']
    };
  }

  private createSyncLoopSuggestion(): OptimizationSuggestion {
    return {
      id: 'perf-async-loops',
      type: 'performance',
      impact: 'high',
      effort: 'medium',
      priority: 9,
      title: 'Replace synchronous loops with async operations',
      description: 'Synchronous loops block the main thread and affect timing',
      rationale: 'Async operations maintain timing precision and UI responsiveness',
      before: `experiment()
  .trial(() => {
    const results = [];
    for (let i = 0; i < 1000; i++) {
      results.push(complexCalculation(i));
    }
    return stimulus.text(results.join(','));
  })`,
      after: `// Pre-calculate or use async iteration
const results = await Promise.all(
  Array.from({ length: 1000 }, (_, i) => 
    complexCalculationAsync(i)
  )
);

experiment()
  .trial(() => {
    return stimulus.text(results.join(','));
  })`,
      automatable: false,
      relatedDocs: ['async-patterns.md', 'performance-guide.md']
    };
  }

  private createModularizationSuggestion(): OptimizationSuggestion {
    return {
      id: 'api-modularize',
      type: 'refactor',
      impact: 'high',
      effort: 'high',
      priority: 7,
      title: 'Split API into core and extended modules',
      description: 'Large API surface makes learning curve steep',
      rationale: 'Progressive disclosure helps users learn incrementally',
      before: `// Single large export
export {
  experiment,
  trial,
  stimulus,
  response,
  timeline,
  // ... 100+ more exports
};`,
      after: `// Core module (80% use cases)
export {
  experiment,
  trial,
  stimulus,
  response
} from '@psyforge/forgescript';

// Extended module (advanced features)
export {
  timeline,
  advanced,
  // ... specialized exports
} from '@psyforge/forgescript/extended';

// Expert module (low-level access)
export {
  unsafe,
  internal,
  // ... expert exports
} from '@psyforge/forgescript/expert';`,
      automatable: true,
      relatedDocs: ['api-architecture.md', 'modular-design.md']
    };
  }

  private createBuilderSimplificationSuggestion(): OptimizationSuggestion {
    return {
      id: 'api-simplify-builder',
      type: 'simplification',
      impact: 'high',
      effort: 'high',
      priority: 8,
      title: 'Replace complex builder chains with configuration objects',
      description: 'Too many builder methods create confusion',
      rationale: 'Configuration objects are more discoverable and type-safe',
      before: `stimulus()
  .type('text')
  .content('Hello')
  .position(100, 100)
  .size(200, 50)
  .color('red')
  .backgroundColor('white')
  .border('1px solid black')
  .fontSize(24)
  .fontFamily('Arial')
  .fontWeight('bold')
  .textAlign('center')
  .opacity(0.9)
  .rotation(0)
  .scale(1)
  .visible(true)`,
      after: `stimulus({
  type: 'text',
  content: 'Hello',
  position: { x: 100, y: 100 },
  size: { width: 200, height: 50 },
  style: {
    color: 'red',
    backgroundColor: 'white',
    border: '1px solid black',
    fontSize: 24,
    fontFamily: 'Arial',
    fontWeight: 'bold',
    textAlign: 'center'
  },
  transform: {
    opacity: 0.9,
    rotation: 0,
    scale: 1
  },
  visible: true
})`,
      automatable: true,
      relatedDocs: ['api-design.md', 'configuration-pattern.md']
    };
  }

  private createProceduralizationSuggestion(trialCount: number): OptimizationSuggestion {
    return {
      id: 'refactor-procedural',
      type: 'pattern',
      impact: 'high',
      effort: 'medium',
      priority: 7,
      title: 'Use procedural generation for many trials',
      description: `${trialCount} trials detected - consider procedural generation`,
      rationale: 'Procedural generation reduces code size and improves maintainability',
      before: `// Manually defining 100+ trials
experiment()
  .trial(/* ... */)
  .trial(/* ... */)
  .trial(/* ... */)
  // ... 97 more trials`,
      after: `// Generate trials procedurally
const conditions = generateConditions();
const trials = conditions.map(condition => 
  createTrialFromCondition(condition)
);

experiment()
  .addTrials(trials)
  .randomize()`,
      automatable: false,
      relatedDocs: ['procedural-generation.md', 'trial-factories.md']
    };
  }

  private createConditionalSimplificationSuggestion(): OptimizationSuggestion {
    return {
      id: 'refactor-conditionals',
      type: 'refactor',
      impact: 'medium',
      effort: 'medium',
      priority: 6,
      title: 'Simplify complex conditional logic',
      description: 'High conditional complexity makes code hard to understand',
      rationale: 'Simpler conditionals reduce bugs and improve maintainability',
      before: `if (participantAge > 18 && participantAge < 65 && 
    hasConsent && !hasVisionProblems && 
    (group === 'A' || group === 'B') && 
    !previousParticipation) {
  // complex nested logic
}`,
      after: `// Extract complex conditions
const isEligibleAge = participantAge > 18 && participantAge < 65;
const isEligibleGroup = ['A', 'B'].includes(group);
const meetsRequirements = hasConsent && !hasVisionProblems && !previousParticipation;

if (isEligibleAge && isEligibleGroup && meetsRequirements) {
  // clearer logic
}`,
      automatable: true,
      relatedDocs: ['clean-code.md', 'refactoring-guide.md']
    };
  }

  private createDeprecationCleanupSuggestion(count: number): OptimizationSuggestion {
    return {
      id: 'api-cleanup-deprecated',
      type: 'migration',
      impact: 'medium',
      effort: 'low',
      priority: 5,
      title: `Remove ${count} deprecated APIs`,
      description: 'Deprecated APIs should be removed after migration period',
      rationale: 'Removing deprecated code reduces confusion and maintenance burden',
      before: `// Still exporting deprecated APIs
export {
  createTrial, // @deprecated
  makeStimulus, // @deprecated
  // ...
}`,
      after: `// Removed deprecated APIs
// Migration guide: docs.psyforge.org/migration/v2

export {
  trial, // replaces createTrial
  stimulus, // replaces makeStimulus
  // ...
}`,
      automatable: true,
      relatedDocs: ['migration-guide.md', 'deprecation-policy.md']
    };
  }

  /**
   * Generate optimization report
   */
  generateReport(suggestions: OptimizationSuggestion[]): string {
    if (suggestions.length === 0) {
      return '✅ No optimization suggestions - code is well-optimized!';
    }

    let report = `# Optimization Suggestions (${suggestions.length})\n\n`;

    // Group by type
    const byType = suggestions.reduce((acc, s) => {
      if (!acc[s.type]) acc[s.type] = [];
      acc[s.type].push(s);
      return acc;
    }, {} as Record<string, OptimizationSuggestion[]>);

    // Generate sections
    Object.entries(byType).forEach(([type, items]) => {
      report += `## ${this.formatType(type)} (${items.length})\n\n`;

      items.forEach(item => {
        report += `### ${this.getPriorityIcon(item.priority)} ${item.title}\n`;
        report += `**Impact**: ${item.impact} | **Effort**: ${item.effort} | **Priority**: ${item.priority}/10\n\n`;
        report += `${item.description}\n\n`;
        report += `**Rationale**: ${item.rationale}\n\n`;

        if (item.automatable) {
          report += `🤖 **This optimization can be automated**\n\n`;
        }

        report += '**Before**:\n```typescript\n' + item.before + '\n```\n\n';
        report += '**After**:\n```typescript\n' + item.after + '\n```\n\n';

        if (item.relatedDocs && item.relatedDocs.length > 0) {
          report += '**Related Documentation**:\n';
          item.relatedDocs.forEach(doc => {
            report += `- ${doc}\n`;
          });
          report += '\n';
        }

        report += '---\n\n';
      });
    });

    return report;
  }

  private formatType(type: string): string {
    const typeNames = {
      refactor: 'Refactoring',
      performance: 'Performance',
      simplification: 'Simplification',
      pattern: 'Pattern Improvements',
      migration: 'Migration'
    };
    return typeNames[type as keyof typeof typeNames] || type;
  }

  private getPriorityIcon(priority: number): string {
    if (priority >= 8) return '🔴';
    if (priority >= 6) return '🟡';
    return '🟢';
  }
}

