/**
 * Visual Complexity Report Generator
 * Creates rich HTML and terminal reports for API complexity analysis
 */

import { APIMetrics } from './APILinter.js';
import { ExperimentMetrics } from './ExperimentComplexityAnalyzer.js';
import { ComplexityScore } from './ComplexityMetricsCalculator.js';
import { OptimizationSuggestion } from './OptimizationEngine.js';

export interface ReportOptions {
  format: 'html' | 'terminal' | 'markdown' | 'json';
  includeHistory?: boolean;
  includeOptimizations?: boolean;
  theme?: 'light' | 'dark';
}

export interface ComplexityReport {
  timestamp: Date;
  version: string;
  apiMetrics: APIMetrics;
  experimentMetrics?: ExperimentMetrics;
  complexityScore: ComplexityScore;
  optimizations?: OptimizationSuggestion[];
  historicalData?: ComplexityScore[];
}

export class ComplexityReportGenerator {
  /**
   * Generate a visual complexity report
   */
  generate(report: ComplexityReport, options: ReportOptions): string {
    switch (options.format) {
      case 'html':
        return this.generateHTMLReport(report, options);
      case 'terminal':
        return this.generateTerminalReport(report, options);
      case 'markdown':
        return this.generateMarkdownReport(report, options);
      case 'json':
        return JSON.stringify(report, null, 2);
      default:
        throw new Error(`Unknown report format: ${options.format}`);
    }
  }

  private generateHTMLReport(report: ComplexityReport, options: ReportOptions): string {
    const theme = options.theme || 'light';
    const isDark = theme === 'dark';

    return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>ForgeScript Complexity Report - ${new Date(report.timestamp).toLocaleDateString()}</title>
  <style>
    :root {
      --bg-primary: ${isDark ? '#1a1a1a' : '#ffffff'};
      --bg-secondary: ${isDark ? '#2a2a2a' : '#f5f5f5'};
      --bg-card: ${isDark ? '#2d2d2d' : '#ffffff'};
      --text-primary: ${isDark ? '#e0e0e0' : '#333333'};
      --text-secondary: ${isDark ? '#a0a0a0' : '#666666'};
      --accent: #1976d2;
      --success: #4caf50;
      --warning: #ff9800;
      --error: #f44336;
      --border: ${isDark ? '#404040' : '#e0e0e0'};
    }

    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      background: var(--bg-primary);
      color: var(--text-primary);
      line-height: 1.6;
    }

    .container {
      max-width: 1400px;
      margin: 0 auto;
      padding: 20px;
    }

    .header {
      background: var(--accent);
      color: white;
      padding: 40px;
      border-radius: 12px;
      margin-bottom: 30px;
      box-shadow: 0 4px 20px rgba(0,0,0,0.1);
    }

    .header h1 {
      font-size: 2.5rem;
      margin-bottom: 10px;
    }

    .header .subtitle {
      opacity: 0.9;
      font-size: 1.1rem;
    }

    .metrics-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
      gap: 20px;
      margin-bottom: 30px;
    }

    .metric-card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 24px;
      box-shadow: 0 2px 8px rgba(0,0,0,0.05);
      transition: transform 0.2s, box-shadow 0.2s;
    }

    .metric-card:hover {
      transform: translateY(-2px);
      box-shadow: 0 4px 16px rgba(0,0,0,0.1);
    }

    .metric-value {
      font-size: 3rem;
      font-weight: bold;
      color: var(--accent);
      margin-bottom: 8px;
    }

    .metric-label {
      color: var(--text-secondary);
      font-size: 1rem;
      margin-bottom: 12px;
    }

    .metric-bar {
      height: 8px;
      background: var(--bg-secondary);
      border-radius: 4px;
      overflow: hidden;
      margin-bottom: 8px;
    }

    .metric-bar-fill {
      height: 100%;
      border-radius: 4px;
      transition: width 0.3s ease;
    }

    .metric-bar-fill.good { background: var(--success); }
    .metric-bar-fill.warning { background: var(--warning); }
    .metric-bar-fill.error { background: var(--error); }

    .score-card {
      background: var(--bg-card);
      border: 2px solid var(--border);
      border-radius: 16px;
      padding: 40px;
      text-align: center;
      margin-bottom: 30px;
      position: relative;
      overflow: hidden;
    }

    .score-grade {
      font-size: 6rem;
      font-weight: bold;
      margin-bottom: 10px;
      background: linear-gradient(135deg, var(--accent), #0d47a1);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
    }

    .score-value {
      font-size: 2rem;
      color: var(--text-secondary);
      margin-bottom: 20px;
    }

    .trend-indicator {
      display: inline-flex;
      align-items: center;
      gap: 8px;
      font-size: 1.2rem;
      padding: 8px 16px;
      background: var(--bg-secondary);
      border-radius: 20px;
    }

    .section {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 30px;
      margin-bottom: 20px;
    }

    .section h2 {
      font-size: 1.8rem;
      margin-bottom: 20px;
      color: var(--text-primary);
    }

    .warning-list, .recommendation-list {
      list-style: none;
    }

    .warning-list li, .recommendation-list li {
      padding: 12px 16px;
      margin-bottom: 8px;
      border-radius: 8px;
      display: flex;
      align-items: center;
      gap: 12px;
    }

    .warning-list li {
      background: rgba(244, 67, 54, 0.1);
      border: 1px solid rgba(244, 67, 54, 0.2);
    }

    .recommendation-list li {
      background: rgba(25, 118, 210, 0.1);
      border: 1px solid rgba(25, 118, 210, 0.2);
    }

    .icon {
      font-size: 1.5rem;
    }

    .chart-container {
      position: relative;
      height: 400px;
      margin-top: 20px;
    }

    .breakdown-chart {
      display: flex;
      gap: 30px;
      align-items: center;
      justify-content: center;
      margin: 30px 0;
    }

    .donut-chart {
      position: relative;
      width: 200px;
      height: 200px;
    }

    .donut-chart svg {
      transform: rotate(-90deg);
    }

    .donut-center {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      text-align: center;
    }

    .donut-score {
      font-size: 2.5rem;
      font-weight: bold;
      color: var(--text-primary);
    }

    .donut-label {
      font-size: 0.9rem;
      color: var(--text-secondary);
    }

    .breakdown-legend {
      display: flex;
      flex-direction: column;
      gap: 12px;
    }

    .legend-item {
      display: flex;
      align-items: center;
      gap: 12px;
    }

    .legend-color {
      width: 20px;
      height: 20px;
      border-radius: 4px;
    }

    .legend-label {
      color: var(--text-primary);
    }

    .legend-value {
      margin-left: auto;
      font-weight: bold;
      color: var(--text-secondary);
    }

    @media (max-width: 768px) {
      .metrics-grid {
        grid-template-columns: 1fr;
      }

      .breakdown-chart {
        flex-direction: column;
      }
    }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>ForgeScript Complexity Report</h1>
      <div class="subtitle">
        Version ${report.version} • Generated ${new Date(report.timestamp).toLocaleString()}
      </div>
    </div>

    ${this.generateScoreCardHTML(report.complexityScore)}
    ${this.generateMetricsGridHTML(report.apiMetrics, report.experimentMetrics)}
    ${this.generateBreakdownChartHTML(report.complexityScore)}
    ${this.generateWarningsHTML(report.apiMetrics, report.experimentMetrics)}
    ${this.generateRecommendationsHTML(report.complexityScore)}
    ${options.includeOptimizations && report.optimizations ? this.generateOptimizationsHTML(report.optimizations) : ''}
    ${options.includeHistory && report.historicalData ? this.generateHistoryChartHTML(report.historicalData) : ''}
  </div>

  <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
  <script>
    ${this.generateChartsJS(report, options)}
  </script>
</body>
</html>`;
  }

  private generateScoreCardHTML(score: ComplexityScore): string {
    const trendIcon = {
      improving: '📈',
      stable: '➡️',
      degrading: '📉'
    }[score.trend];

    return `
    <div class="score-card">
      <div class="score-grade">${score.grade}</div>
      <div class="score-value">${score.overall.toFixed(1)}/100</div>
      <div class="trend-indicator">
        <span class="icon">${trendIcon}</span>
        <span>${score.trend}</span>
      </div>
    </div>`;
  }

  private generateMetricsGridHTML(apiMetrics: APIMetrics, experimentMetrics?: ExperimentMetrics): string {
    const getBarClass = (value: number, thresholds: { good: number; warning: number }) => {
      if (value <= thresholds.good) return 'good';
      if (value <= thresholds.warning) return 'warning';
      return 'error';
    };

    return `
    <div class="metrics-grid">
      <div class="metric-card">
        <div class="metric-value">${apiMetrics.totalExports}</div>
        <div class="metric-label">Total API Exports</div>
        <div class="metric-bar">
          <div class="metric-bar-fill ${getBarClass(apiMetrics.totalExports, { good: 80, warning: 100 })}" 
               style="width: ${Math.min(100, (apiMetrics.totalExports / 150) * 100)}%"></div>
        </div>
      </div>

      <div class="metric-card">
        <div class="metric-value">${apiMetrics.publicMethods}</div>
        <div class="metric-label">Public Methods</div>
        <div class="metric-bar">
          <div class="metric-bar-fill ${getBarClass(apiMetrics.publicMethods, { good: 150, warning: 200 })}" 
               style="width: ${Math.min(100, (apiMetrics.publicMethods / 300) * 100)}%"></div>
        </div>
      </div>

      ${experimentMetrics ? `
      <div class="metric-card">
        <div class="metric-value">${experimentMetrics.maxNestingDepth}</div>
        <div class="metric-label">Max Nesting Depth</div>
        <div class="metric-bar">
          <div class="metric-bar-fill ${getBarClass(experimentMetrics.maxNestingDepth, { good: 5, warning: 8 })}" 
               style="width: ${Math.min(100, (experimentMetrics.maxNestingDepth / 12) * 100)}%"></div>
        </div>
      </div>

      <div class="metric-card">
        <div class="metric-value">${experimentMetrics.timingPrecisionRisk}</div>
        <div class="metric-label">Timing Risk</div>
        <div class="metric-bar">
          <div class="metric-bar-fill ${experimentMetrics.timingPrecisionRisk === 'low' ? 'good' : experimentMetrics.timingPrecisionRisk === 'medium' ? 'warning' : 'error'}" 
               style="width: ${experimentMetrics.timingPrecisionRisk === 'low' ? 33 : experimentMetrics.timingPrecisionRisk === 'medium' ? 66 : 100}%"></div>
        </div>
      </div>
      ` : ''}
    </div>`;
  }

  private generateBreakdownChartHTML(score: ComplexityScore): string {
    const colors = {
      api: '#1976d2',
      experiment: '#7c4dff',
      performance: '#00bcd4',
      maintainability: '#4caf50',
      usability: '#ff9800'
    };

    return `
    <div class="section">
      <h2>Complexity Breakdown</h2>
      <div class="breakdown-chart">
        <div class="donut-chart">
          <svg width="200" height="200" viewBox="0 0 200 200">
            ${this.generateDonutSegments(score.breakdown, colors)}
          </svg>
          <div class="donut-center">
            <div class="donut-score">${score.overall.toFixed(0)}</div>
            <div class="donut-label">Overall</div>
          </div>
        </div>
        <div class="breakdown-legend">
          ${Object.entries(score.breakdown).map(([key, value]) => `
            <div class="legend-item">
              <div class="legend-color" style="background: ${colors[key as keyof typeof colors]}"></div>
              <span class="legend-label">${this.formatLabel(key)}</span>
              <span class="legend-value">${value.toFixed(1)}</span>
            </div>
          `).join('')}
        </div>
      </div>
    </div>`;
  }

  private generateDonutSegments(breakdown: ComplexityScore['breakdown'], colors: Record<string, string>): string {
    const total = Object.values(breakdown).reduce((sum, val) => sum + val, 0);
    let currentAngle = 0;

    return Object.entries(breakdown).map(([key, value]) => {
      const percentage = (value / total) * 100;
      const angle = (percentage / 100) * 360;
      const startAngle = currentAngle;
      const endAngle = currentAngle + angle;
      currentAngle = endAngle;

      const largeArcFlag = angle > 180 ? 1 : 0;
      const x1 = 100 + 80 * Math.cos((startAngle * Math.PI) / 180);
      const y1 = 100 + 80 * Math.sin((startAngle * Math.PI) / 180);
      const x2 = 100 + 80 * Math.cos((endAngle * Math.PI) / 180);
      const y2 = 100 + 80 * Math.sin((endAngle * Math.PI) / 180);

      return `
        <path d="M 100 100 L ${x1} ${y1} A 80 80 0 ${largeArcFlag} 1 ${x2} ${y2} Z"
              fill="${colors[key as keyof typeof colors]}"
              opacity="0.9"/>
      `;
    }).join('');
  }

  private generateWarningsHTML(apiMetrics: APIMetrics, experimentMetrics?: ExperimentMetrics): string {
    const allWarnings = [
      ...apiMetrics.warnings,
      ...(experimentMetrics?.warnings || [])
    ];

    if (allWarnings.length === 0) return '';

    return `
    <div class="section">
      <h2>⚠️ Warnings</h2>
      <ul class="warning-list">
        ${allWarnings.map(warning => `
          <li>
            <span class="icon">⚠️</span>
            <span>${warning}</span>
          </li>
        `).join('')}
      </ul>
    </div>`;
  }

  private generateRecommendationsHTML(score: ComplexityScore): string {
    if (score.recommendations.length === 0) return '';

    return `
    <div class="section">
      <h2>💡 Recommendations</h2>
      <ul class="recommendation-list">
        ${score.recommendations.map(rec => `
          <li>
            <span class="icon">💡</span>
            <span>${rec}</span>
          </li>
        `).join('')}
      </ul>
    </div>`;
  }

  private generateOptimizationsHTML(optimizations: OptimizationSuggestion[]): string {
    if (optimizations.length === 0) return '';

    return `
    <div class="section">
      <h2>🚀 Optimization Suggestions</h2>
      ${optimizations.slice(0, 5).map(opt => `
        <div style="margin-bottom: 20px; padding: 20px; background: var(--bg-secondary); border-radius: 8px;">
          <h3>${this.getPriorityIcon(opt.priority)} ${opt.title}</h3>
          <p style="margin: 10px 0; color: var(--text-secondary);">
            <strong>Impact:</strong> ${opt.impact} | 
            <strong>Effort:</strong> ${opt.effort} | 
            <strong>Priority:</strong> ${opt.priority}/10
          </p>
          <p>${opt.description}</p>
          ${opt.automatable ? '<p style="color: var(--success);">🤖 This can be automated</p>' : ''}
        </div>
      `).join('')}
    </div>`;
  }

  private generateHistoryChartHTML(history: ComplexityScore[]): string {
    return `
    <div class="section">
      <h2>📊 Historical Trend</h2>
      <div class="chart-container">
        <canvas id="historyChart"></canvas>
      </div>
    </div>`;
  }

  private generateChartsJS(report: ComplexityReport, options: ReportOptions): string {
    if (!options.includeHistory || !report.historicalData) return '';

    return `
    const ctx = document.getElementById('historyChart').getContext('2d');
    new Chart(ctx, {
      type: 'line',
      data: {
        labels: [${report.historicalData.map((_, i) => `'v${i + 1}'`).join(', ')}],
        datasets: [{
          label: 'Overall Score',
          data: [${report.historicalData.map(h => h.overall.toFixed(1)).join(', ')}],
          borderColor: '#1976d2',
          backgroundColor: 'rgba(25, 118, 210, 0.1)',
          tension: 0.3
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: {
            display: false
          }
        },
        scales: {
          y: {
            beginAtZero: true,
            max: 100
          }
        }
      }
    });`;
  }

  private generateTerminalReport(report: ComplexityReport, options: ReportOptions): string {
    const { complexityScore: score, apiMetrics, experimentMetrics } = report;

    let output = '';

    // Header
    output += '\n' + '═'.repeat(60) + '\n';
    output += '  ForgeScript Complexity Report\n';
    output += '  ' + new Date(report.timestamp).toLocaleString() + '\n';
    output += '═'.repeat(60) + '\n\n';

    // Overall Score
    output += `Overall Score: ${score.overall.toFixed(1)}/100 [${this.generateBar(score.overall, 30)}] Grade: ${score.grade}\n`;
    output += `Trend: ${this.getTrendIcon(score.trend)} ${score.trend}\n\n`;

    // Breakdown
    output += 'Breakdown:\n';
    Object.entries(score.breakdown).forEach(([key, value]) => {
      output += `  ${this.formatLabel(key).padEnd(15)} ${value.toFixed(1).padStart(5)} [${this.generateBar(value, 20)}]\n`;
    });
    output += '\n';

    // Key Metrics
    output += 'Key Metrics:\n';
    output += `  API Exports:     ${apiMetrics.totalExports}\n`;
    output += `  Public Methods:  ${apiMetrics.publicMethods}\n`;
    output += `  Public Classes:  ${apiMetrics.publicClasses}\n`;
    if (experimentMetrics) {
      output += `  Max Nesting:     ${experimentMetrics.maxNestingDepth}\n`;
      output += `  Timing Risk:     ${experimentMetrics.timingPrecisionRisk}\n`;
    }
    output += '\n';

    // Warnings
    const allWarnings = [...apiMetrics.warnings, ...(experimentMetrics?.warnings || [])];
    if (allWarnings.length > 0) {
      output += 'Warnings:\n';
      allWarnings.forEach(warning => {
        output += `  ⚠️  ${warning}\n`;
      });
      output += '\n';
    }

    // Recommendations
    if (score.recommendations.length > 0) {
      output += 'Recommendations:\n';
      score.recommendations.forEach(rec => {
        output += `  • ${rec}\n`;
      });
      output += '\n';
    }

    // Optimizations summary
    if (options.includeOptimizations && report.optimizations) {
      output += `\nTop Optimizations (${report.optimizations.length} total):\n`;
      report.optimizations.slice(0, 3).forEach(opt => {
        output += `  ${this.getPriorityIcon(opt.priority)} ${opt.title}\n`;
        output += `     Impact: ${opt.impact} | Effort: ${opt.effort}\n`;
      });
    }

    output += '\n' + '═'.repeat(60) + '\n';

    return output;
  }

  private generateMarkdownReport(report: ComplexityReport, options: ReportOptions): string {
    const { complexityScore: score, apiMetrics, experimentMetrics } = report;

    let md = '# ForgeScript Complexity Report\n\n';
    md += `**Version:** ${report.version}  \n`;
    md += `**Generated:** ${new Date(report.timestamp).toLocaleString()}\n\n`;

    // Summary
    md += '## Summary\n\n';
    md += `- **Overall Score:** ${score.overall.toFixed(1)}/100 (Grade: ${score.grade})\n`;
    md += `- **Trend:** ${score.trend}\n\n`;

    // Breakdown table
    md += '## Score Breakdown\n\n';
    md += '| Category | Score | Visual |\n';
    md += '|----------|-------|--------|\n';
    Object.entries(score.breakdown).forEach(([key, value]) => {
      md += `| ${this.formatLabel(key)} | ${value.toFixed(1)} | ${this.generateBar(value, 20)} |\n`;
    });
    md += '\n';

    // Metrics table
    md += '## Key Metrics\n\n';
    md += '| Metric | Value | Status |\n';
    md += '|--------|-------|--------|\n';
    md += `| API Exports | ${apiMetrics.totalExports} | ${this.getStatus(apiMetrics.totalExports, 80, 100)} |\n`;
    md += `| Public Methods | ${apiMetrics.publicMethods} | ${this.getStatus(apiMetrics.publicMethods, 150, 200)} |\n`;
    md += `| Public Classes | ${apiMetrics.publicClasses} | ${this.getStatus(apiMetrics.publicClasses, 20, 30)} |\n`;
    if (experimentMetrics) {
      md += `| Max Nesting Depth | ${experimentMetrics.maxNestingDepth} | ${this.getStatus(experimentMetrics.maxNestingDepth, 5, 8)} |\n`;
      md += `| Timing Risk | ${experimentMetrics.timingPrecisionRisk} | ${experimentMetrics.timingPrecisionRisk === 'low' ? '✅' : experimentMetrics.timingPrecisionRisk === 'medium' ? '⚠️' : '❌'} |\n`;
    }
    md += '\n';

    // Warnings and recommendations
    const allWarnings = [...apiMetrics.warnings, ...(experimentMetrics?.warnings || [])];
    if (allWarnings.length > 0) {
      md += '## ⚠️ Warnings\n\n';
      allWarnings.forEach(warning => {
        md += `- ${warning}\n`;
      });
      md += '\n';
    }

    if (score.recommendations.length > 0) {
      md += '## 💡 Recommendations\n\n';
      score.recommendations.forEach(rec => {
        md += `- ${rec}\n`;
      });
      md += '\n';
    }

    // Optimizations
    if (options.includeOptimizations && report.optimizations) {
      md += '## 🚀 Top Optimization Opportunities\n\n';
      report.optimizations.slice(0, 5).forEach(opt => {
        md += `### ${this.getPriorityIcon(opt.priority)} ${opt.title}\n\n`;
        md += `**Impact:** ${opt.impact} | **Effort:** ${opt.effort} | **Priority:** ${opt.priority}/10\n\n`;
        md += `${opt.description}\n\n`;
        if (opt.automatable) {
          md += '🤖 **This optimization can be automated**\n\n';
        }
      });
    }

    return md;
  }

  private generateBar(score: number, width: number = 20): string {
    const filled = Math.round((score / 100) * width);
    const empty = width - filled;
    return '█'.repeat(filled) + '░'.repeat(empty);
  }

  private getTrendIcon(trend: 'improving' | 'stable' | 'degrading'): string {
    switch (trend) {
      case 'improving': return '📈';
      case 'stable': return '➡️';
      case 'degrading': return '📉';
    }
  }

  private getPriorityIcon(priority: number): string {
    if (priority >= 8) return '🔴';
    if (priority >= 6) return '🟡';
    return '🟢';
  }

  private formatLabel(key: string): string {
    return key.charAt(0).toUpperCase() + key.slice(1).replace(/([A-Z])/g, ' $1').trim();
  }

  private getStatus(value: number, good: number, warning: number): string {
    if (value <= good) return '✅';
    if (value <= warning) return '⚠️';
    return '❌';
  }
}

