/**
 * Performance Impact Analyzer
 * Analyzes how API complexity affects runtime performance
 */

import { ExperimentMetrics } from './ExperimentComplexityAnalyzer.js';
import { APIMetrics } from './APILinter.js';

export interface PerformanceImpact {
  // Timing impact
  estimatedJitter: number; // ms
  timingRisk: 'low' | 'medium' | 'high' | 'critical';
  timingBreakdown: {
    apiOverhead: number;
    renderTime: number;
    gcPressure: number;
    eventLoopBlocking: number;
  };

  // Memory impact
  estimatedMemoryUsage: number; // MB
  memoryRisk: 'low' | 'medium' | 'high' | 'critical';
  memoryBreakdown: {
    apiInstances: number;
    experimentData: number;
    stimuliCache: number;
    responseBuffers: number;
  };

  // CPU impact
  estimatedCPULoad: number; // percentage
  cpuRisk: 'low' | 'medium' | 'high' | 'critical';
  cpuBreakdown: {
    rendering: number;
    dataProcessing: number;
    eventHandling: number;
    garbage: number;
  };

  // Frame rate impact
  estimatedFPS: number;
  frameDropRisk: 'low' | 'medium' | 'high' | 'critical';

  // Network impact (for online experiments)
  estimatedBandwidth: number; // KB/s
  networkRisk: 'low' | 'medium' | 'high' | 'critical';

  // Overall assessment
  overallRisk: 'low' | 'medium' | 'high' | 'critical';
  criticalIssues: string[];
  performanceRecommendations: PerformanceRecommendation[];
}

export interface PerformanceRecommendation {
  category: 'timing' | 'memory' | 'cpu' | 'rendering' | 'network';
  severity: 'info' | 'warning' | 'error' | 'critical';
  issue: string;
  impact: string;
  solution: string;
  estimatedImprovement: string;
}

export class PerformanceImpactAnalyzer {
  // Performance constants based on research
  private readonly TIMING_TARGET = 2; // ms precision target
  private readonly FRAME_TARGET = 16.67; // ms for 60fps
  private readonly MEMORY_WARNING = 100; // MB
  private readonly CPU_WARNING = 50; // %

  /**
   * Analyze performance impact of API and experiment complexity
   */
  analyze(apiMetrics: APIMetrics, experimentMetrics?: ExperimentMetrics): PerformanceImpact {
    const timingImpact = this.analyzeTimingImpact(apiMetrics, experimentMetrics);
    const memoryImpact = this.analyzeMemoryImpact(apiMetrics, experimentMetrics);
    const cpuImpact = this.analyzeCPUImpact(apiMetrics, experimentMetrics);
    const frameImpact = this.analyzeFrameRateImpact(apiMetrics, experimentMetrics);
    const networkImpact = this.analyzeNetworkImpact(apiMetrics, experimentMetrics);

    const criticalIssues = this.identifyCriticalIssues(
      timingImpact,
      memoryImpact,
      cpuImpact,
      frameImpact
    );

    const recommendations = this.generateRecommendations(
      timingImpact,
      memoryImpact,
      cpuImpact,
      frameImpact,
      networkImpact,
      apiMetrics,
      experimentMetrics
    );

    const overallRisk = this.calculateOverallRisk(
      timingImpact.timingRisk,
      memoryImpact.memoryRisk,
      cpuImpact.cpuRisk,
      frameImpact.frameDropRisk
    );

    return {
      ...timingImpact,
      ...memoryImpact,
      ...cpuImpact,
      ...frameImpact,
      ...networkImpact,
      overallRisk,
      criticalIssues,
      performanceRecommendations: recommendations
    };
  }

  private analyzeTimingImpact(apiMetrics: APIMetrics, experimentMetrics?: ExperimentMetrics) {
    // Base overhead from API complexity
    const apiOverhead = (apiMetrics.publicMethods * 0.001) + (apiMetrics.builderMethods * 0.002);

    // Rendering overhead
    const renderTime = experimentMetrics 
      ? experimentMetrics.estimatedRenderCost 
      : 16;

    // GC pressure from object creation
    const gcPressure = experimentMetrics
      ? (experimentMetrics.totalStimuli * 0.1) + (experimentMetrics.callbackComplexity * 0.05)
      : 0;

    // Event loop blocking from sync operations
    const eventLoopBlocking = experimentMetrics
      ? (experimentMetrics.loopComplexity * 2) + (experimentMetrics.conditionalComplexity * 0.5)
      : 0;

    const totalJitter = apiOverhead + (renderTime > 16 ? renderTime - 16 : 0) + gcPressure + eventLoopBlocking;

    const timingRisk = this.calculateTimingRisk(totalJitter);

    return {
      estimatedJitter: Math.round(totalJitter * 100) / 100,
      timingRisk,
      timingBreakdown: {
        apiOverhead: Math.round(apiOverhead * 100) / 100,
        renderTime: Math.round(renderTime * 100) / 100,
        gcPressure: Math.round(gcPressure * 100) / 100,
        eventLoopBlocking: Math.round(eventLoopBlocking * 100) / 100
      }
    };
  }

  private analyzeMemoryImpact(apiMetrics: APIMetrics, experimentMetrics?: ExperimentMetrics) {
    // API memory footprint
    const apiInstances = (apiMetrics.publicClasses * 0.5) + (apiMetrics.totalExports * 0.1);

    // Experiment data storage
    const experimentData = experimentMetrics
      ? (experimentMetrics.totalTrials * 0.1) + (experimentMetrics.totalResponses * 0.05)
      : 0;

    // Stimuli caching
    const stimuliCache = experimentMetrics
      ? experimentMetrics.totalStimuli * 0.5
      : 0;

    // Response buffers
    const responseBuffers = experimentMetrics
      ? experimentMetrics.totalResponses * 0.2
      : 0;

    const totalMemory = apiInstances + experimentData + stimuliCache + responseBuffers;
    const memoryRisk = this.calculateMemoryRisk(totalMemory);

    return {
      estimatedMemoryUsage: Math.round(totalMemory * 10) / 10,
      memoryRisk,
      memoryBreakdown: {
        apiInstances: Math.round(apiInstances * 10) / 10,
        experimentData: Math.round(experimentData * 10) / 10,
        stimuliCache: Math.round(stimuliCache * 10) / 10,
        responseBuffers: Math.round(responseBuffers * 10) / 10
      }
    };
  }

  private analyzeCPUImpact(apiMetrics: APIMetrics, experimentMetrics?: ExperimentMetrics) {
    // Rendering load
    const rendering = experimentMetrics
      ? Math.min(50, experimentMetrics.totalStimuli * 0.5)
      : 10;

    // Data processing
    const dataProcessing = experimentMetrics
      ? (experimentMetrics.conditionalComplexity * 0.5) + (experimentMetrics.loopComplexity * 1)
      : 5;

    // Event handling
    const eventHandling = experimentMetrics
      ? experimentMetrics.totalResponses * 0.3
      : 5;

    // Garbage collection overhead
    const garbage = (apiMetrics.publicMethods / 100) * 5;

    const totalCPU = rendering + dataProcessing + eventHandling + garbage;
    const cpuRisk = this.calculateCPURisk(totalCPU);

    return {
      estimatedCPULoad: Math.round(totalCPU),
      cpuRisk,
      cpuBreakdown: {
        rendering: Math.round(rendering),
        dataProcessing: Math.round(dataProcessing),
        eventHandling: Math.round(eventHandling),
        garbage: Math.round(garbage)
      }
    };
  }

  private analyzeFrameRateImpact(apiMetrics: APIMetrics, experimentMetrics?: ExperimentMetrics) {
    const renderCost = experimentMetrics?.estimatedRenderCost || 16;
    const overhead = (apiMetrics.builderMethods * 0.1);
    const totalFrameTime = renderCost + overhead;

    const estimatedFPS = Math.round(1000 / totalFrameTime);
    const frameDropRisk = this.calculateFrameDropRisk(estimatedFPS);

    return {
      estimatedFPS,
      frameDropRisk
    };
  }

  private analyzeNetworkImpact(apiMetrics: APIMetrics, experimentMetrics?: ExperimentMetrics) {
    // Estimate data transfer for online experiments
    const apiPayload = apiMetrics.totalExports * 0.1; // KB per export
    const experimentPayload = experimentMetrics
      ? (experimentMetrics.totalTrials * 0.5) + (experimentMetrics.totalStimuli * 2)
      : 0;

    const totalBandwidth = apiPayload + experimentPayload;
    const networkRisk = this.calculateNetworkRisk(totalBandwidth);

    return {
      estimatedBandwidth: Math.round(totalBandwidth * 10) / 10,
      networkRisk
    };
  }

  private calculateTimingRisk(jitter: number): 'low' | 'medium' | 'high' | 'critical' {
    if (jitter < 1) return 'low';
    if (jitter < 2) return 'medium';
    if (jitter < 5) return 'high';
    return 'critical';
  }

  private calculateMemoryRisk(memory: number): 'low' | 'medium' | 'high' | 'critical' {
    if (memory < 50) return 'low';
    if (memory < 100) return 'medium';
    if (memory < 200) return 'high';
    return 'critical';
  }

  private calculateCPURisk(cpu: number): 'low' | 'medium' | 'high' | 'critical' {
    if (cpu < 25) return 'low';
    if (cpu < 50) return 'medium';
    if (cpu < 75) return 'high';
    return 'critical';
  }

  private calculateFrameDropRisk(fps: number): 'low' | 'medium' | 'high' | 'critical' {
    if (fps >= 60) return 'low';
    if (fps >= 30) return 'medium';
    if (fps >= 15) return 'high';
    return 'critical';
  }

  private calculateNetworkRisk(bandwidth: number): 'low' | 'medium' | 'high' | 'critical' {
    if (bandwidth < 100) return 'low';
    if (bandwidth < 500) return 'medium';
    if (bandwidth < 1000) return 'high';
    return 'critical';
  }

  private calculateOverallRisk(
    timing: string,
    memory: string,
    cpu: string,
    frames: string
  ): 'low' | 'medium' | 'high' | 'critical' {
    const risks = [timing, memory, cpu, frames];
    if (risks.includes('critical')) return 'critical';
    if (risks.includes('high')) return 'high';
    if (risks.includes('medium')) return 'medium';
    return 'low';
  }

  private identifyCriticalIssues(
    timing: any,
    memory: any,
    cpu: any,
    frames: any
  ): string[] {
    const issues: string[] = [];

    if (timing.estimatedJitter > this.TIMING_TARGET) {
      issues.push(`Timing jitter (${timing.estimatedJitter}ms) exceeds ${this.TIMING_TARGET}ms target`);
    }

    if (memory.estimatedMemoryUsage > this.MEMORY_WARNING) {
      issues.push(`Memory usage (${memory.estimatedMemoryUsage}MB) exceeds ${this.MEMORY_WARNING}MB warning threshold`);
    }

    if (cpu.estimatedCPULoad > this.CPU_WARNING) {
      issues.push(`CPU load (${cpu.estimatedCPULoad}%) exceeds ${this.CPU_WARNING}% warning threshold`);
    }

    if (frames.estimatedFPS < 60) {
      issues.push(`Frame rate (${frames.estimatedFPS}fps) below 60fps target`);
    }

    return issues;
  }

  private generateRecommendations(
    timing: any,
    memory: any,
    cpu: any,
    frames: any,
    network: any,
    apiMetrics: APIMetrics,
    experimentMetrics?: ExperimentMetrics
  ): PerformanceRecommendation[] {
