      if (cpu.cpuBreakdown.rendering > 25) {
        recommendations.push({
          category: 'cpu',
          severity: 'warning',
          issue: 'High rendering load',
          impact: `${cpu.cpuBreakdown.rendering}% CPU for rendering`,
          solution: 'Use sprite batching and optimize draw calls',
          estimatedImprovement: 'Reduce CPU by 40%'
        });
      }

      if (experimentMetrics && experimentMetrics.loopComplexity > 5) {
        recommendations.push({
          category: 'cpu',
          severity: 'error',
          issue: 'Complex loops in experiment logic',
          impact: `${cpu.cpuBreakdown.dataProcessing}% CPU for processing`,
          solution: 'Optimize algorithms and use web workers for heavy computation',
          estimatedImprovement: 'Reduce CPU by 60%'
        });
      }
    }

    // Frame rate recommendations
    if (frames.frameDropRisk !== 'low') {
