        issue: 'Frame rate below target',
        impact: `${frames.estimatedFPS}fps vs 60fps target`,
        solution: 'Reduce render complexity and use requestAnimationFrame',
        estimatedImprovement: 'Achieve stable 60fps'
      });
    }

    // Network recommendations
    if (network.networkRisk !== 'low') {
      recommendations.push({
        category: 'network',
        severity: 'info',
        issue: 'High bandwidth requirements',
        impact: `${network.estimatedBandwidth}KB/s required`,
        solution: 'Compress assets and implement progressive loading',
        estimatedImprovement: 'Reduce bandwidth by 70%'
      });
    }

    // Sort by severity
    const severityOrder = { critical: 0, error: 1, warning: 2, info: 3 };
    recommendations.sort((a, b) => 
      severityOrder[a.severity] - severityOrder[b.severity]
    );

    return recommendations;
  }

  /**
   * Generate performance report
   */
  generateReport(impact: PerformanceImpact): string {
    let report = '# Performance Impact Analysis\n\n';

    // Overall assessment
    report += `## Overall Risk: ${this.getRiskEmoji(impact.overallRisk)} ${impact.overallRisk.toUpperCase()}\n\n`;

    // Critical issues
    if (impact.criticalIssues.length > 0) {
      report += '## 🚨 Critical Issues\n';
      impact.criticalIssues.forEach(issue => {
        report += `- ${issue}\n`;
      });
      report += '\n';
    }

    // Performance metrics
    report += '## Performance Metrics\n\n';
    report += '### Timing Precision\n';
    report += `- **Estimated Jitter**: ${impact.estimatedJitter}ms (target: <2ms)\n`;
    report += `- **Risk Level**: ${this.getRiskEmoji(impact.timingRisk)} ${impact.timingRisk}\n`;
    report += `- **Breakdown**:\n`;
