    report += `  - Response Buffers: ${impact.memoryBreakdown.responseBuffers}MB\n\n`;

    report += '### CPU Load\n';
    report += `- **Estimated Load**: ${impact.estimatedCPULoad}%\n`;
    report += `- **Risk Level**: ${this.getRiskEmoji(impact.cpuRisk)} ${impact.cpuRisk}\n`;
    report += `- **Breakdown**:\n`;
    report += `  - Rendering: ${impact.cpuBreakdown.rendering}%\n`;
    report += `  - Data Processing: ${impact.cpuBreakdown.dataProcessing}%\n`;
    report += `  - Event Handling: ${impact.cpuBreakdown.eventHandling}%\n`;
    report += `  - Garbage Collection: ${impact.cpuBreakdown.garbage}%\n\n`;

    report += '### Frame Rate\n';
    report += `- **Estimated FPS**: ${impact.estimatedFPS}\n`;
    report += `- **Risk Level**: ${this.getRiskEmoji(impact.frameDropRisk)} ${impact.frameDropRisk}\n\n`;

    // Recommendations
    if (impact.performanceRecommendations.length > 0) {
      report += '## Recommendations\n\n';
      impact.performanceRecommendations.forEach(rec => {
        const icon = this.getSeverityIcon(rec.severity);
        report += `### ${icon} ${rec.issue}\n`;
        report += `- **Category**: ${rec.category}\n`;
        report += `- **Impact**: ${rec.impact}\n`;
        report += `- **Solution**: ${rec.solution}\n`;
        report += `- **Expected Improvement**: ${rec.estimatedImprovement}\n\n`;
      });
    }

    return report;
  }

  private getRiskEmoji(risk: string): string {
    switch (risk) {
      case 'low': return '✅';
      case 'medium': return '⚠️';
      case 'high': return '🔴';
      case 'critical': return '🚨';
      default: return '❓';
    }
  }

  private getSeverityIcon(severity: string): string {
    switch (severity) {
      case 'info': return 'ℹ️';
      case 'warning': return '⚠️';
      case 'error': return '❌';
      case 'critical': return '🚨';
      default: return '•';
    }
  }
}

