        { overall: 75, breakdown: {} as any, grade: 'C' as const, trend: 'stable' as const, recommendations: [] },
        { overall: 80, breakdown: {} as any, grade: 'B' as const, trend: 'stable' as const, recommendations: [] },
        { overall: 85, breakdown: {} as any, grade: 'B' as const, trend: 'stable' as const, recommendations: [] }
      ];

