      const score = 
        (metrics.totalExports * weights.exports) +
        (metrics.publicMethods * weights.methods) +
        (metrics.publicClasses * weights.classes) +
        (metrics.publicInterfaces * weights.interfaces) +
        (metrics.builderMethods * weights.builders) +
        (metrics.deprecatedAPIs * weights.deprecated);

      expect(score).toBe(138.5);
    });

    it('should generate recommendations for high complexity', () => {
      const metrics = {
        totalExports: 120,
        publicMethods: 250,
        publicClasses: 25,
        publicInterfaces: 10,
        builderMethods: 60,
        deprecatedAPIs: 8,
        complexityScore: 200,
        recommendations: [],
        warnings: [],
        duplicatePatterns: []
      };

      const recommendations: string[] = [];

      if (metrics.totalExports > 80) {
        recommendations.push('Consider splitting the API into modules (e.g., core, advanced, experimental)');
      }

      if (metrics.builderMethods > 40) {
        recommendations.push('Consider using configuration objects instead of many builder methods');
      }

      if (metrics.deprecatedAPIs > 5) {
        recommendations.push('Schedule removal of deprecated APIs in next major version');
      }

      expect(recommendations).toHaveLength(3);
      expect(recommendations).toContain('Consider splitting the API into modules (e.g., core, advanced, experimental)');
    });
  });

  describe('ExperimentComplexityAnalyzer', () => {
    let analyzer: ExperimentComplexityAnalyzer;

    beforeEach(() => {
      analyzer = new ExperimentComplexityAnalyzer();
    });

    it('should analyze simple experiment', () => {
      const code = `
        const exp = experiment('Simple RT')
          .trial()
            .stimulus.text('Press SPACE')
            .response.keyboard(['space'])
          .build();
      `;

      const metrics = analyzer.analyzeExperiment(code);

      expect(metrics.totalTrials).toBeGreaterThan(0);
      expect(metrics.totalStimuli).toBeGreaterThan(0);
      expect(metrics.totalResponses).toBeGreaterThan(0);
      expect(metrics.maxNestingDepth).toBeLessThan(5);
      expect(metrics.timingPrecisionRisk).toBe('low');
    });

    it('should detect deep nesting', () => {
      const code = `
        experiment()
          .trial(() => {
            if (condition1) {
              if (condition2) {
                if (condition3) {
                  if (condition4) {
                    if (condition5) {
                      // deeply nested
                    }
                  }
                }
              }
            }
          });
      `;

      const metrics = analyzer.analyzeExperiment(code);

      expect(metrics.maxNestingDepth).toBeGreaterThan(5);
      expect(metrics.antiPatterns).toContain('Deep callback nesting');
    });

    it('should detect synchronous loops', () => {
      const code = `
        experiment()
          .trial(() => {
            for (let i = 0; i < 10000; i++) {
              heavyComputation(i);
            }
          });
      `;

      const metrics = analyzer.analyzeExperiment(code);

      expect(metrics.loopComplexity).toBeGreaterThan(0);
      expect(metrics.antiPatterns).toContain('Synchronous loop in experiment');
      expect(metrics.timingPrecisionRisk).not.toBe('low');
    });

    it('should calculate performance impact', () => {
      const code = `
        experiment()
          ${Array(50).fill('.trial().stimulus.image("test.png")').join('\n')}
          .build();
      `;

      const metrics = analyzer.analyzeExperiment(code);

      expect(metrics.estimatedMemoryUsage).toBeGreaterThan(50);
      expect(metrics.estimatedRenderCost).toBeGreaterThan(16);
    });

    it('should suggest JSON format for simple experiments', () => {
      const code = `
        experiment('Simple')
          .trial()
            .stimulus.text('Hello')
            .response.keyboard(['y', 'n'])
          .build();
      `;

      const metrics = analyzer.analyzeExperiment(code);

      const jsonSuggestion = metrics.optimizations.find(
        opt => opt.type === 'simplification' && opt.message.includes('JSON')
      );

      expect(jsonSuggestion).toBeDefined();
    });
  });

  describe('ComplexityMetricsCalculator', () => {
    let calculator: ComplexityMetricsCalculator;

    beforeEach(() => {
      calculator = new ComplexityMetricsCalculator();
    });

    it('should calculate overall complexity score', () => {
      const apiMetrics = {
        totalExports: 50,
