/**
 * API Complexity Management Tools
 * Export all governance and complexity analysis tools
 */

export { APILinter, type APIMetrics, type LintRule } from './APILinter.js';
export { 
  ExperimentComplexityAnalyzer, 
  type ExperimentMetrics, 
  type OptimizationSuggestion as ExperimentOptimization 
} from './ExperimentComplexityAnalyzer.js';
export { 
  ComplexityMetricsCalculator, 
  type ComplexityScore, 
  type HistoricalMetrics 
} from './ComplexityMetricsCalculator.js';
export { 
  OptimizationEngine, 
  type OptimizationSuggestion, 
  type OptimizationContext 
} from './OptimizationEngine.js';
export { 
  PerformanceImpactAnalyzer, 
  type PerformanceImpact, 
  type PerformanceRecommendation 
} from './PerformanceImpactAnalyzer.js';
export { 
  ComplexityReportGenerator, 
  type ReportOptions, 
  type ComplexityReport 
} from './ComplexityReportGenerator.js';

/**
 * Convenience function to run full complexity analysis
 */
export async function analyzeComplexity(options: {
  apiFiles?: string[];
  experimentFile?: string;
  format?: 'html' | 'terminal' | 'markdown' | 'json';
  outputPath?: string;
}): Promise<ComplexityReport> {
  const { APILinter } = await import('./APILinter.js');
  const { ExperimentComplexityAnalyzer } = await import('./ExperimentComplexityAnalyzer.js');
  const { ComplexityMetricsCalculator } = await import('./ComplexityMetricsCalculator.js');
  const { OptimizationEngine } = await import('./OptimizationEngine.js');
  const { PerformanceImpactAnalyzer } = await import('./PerformanceImpactAnalyzer.js');
  const { ComplexityReportGenerator } = await import('./ComplexityReportGenerator.js');

  // Run API analysis
  const apiLinter = new APILinter();
  const apiMetrics = options.apiFiles 
    ? apiLinter.analyzeFiles(options.apiFiles)
    : apiLinter.analyzeFiles([]);

  // Run experiment analysis if provided
  let experimentMetrics;
  if (options.experimentFile) {
    const experimentAnalyzer = new ExperimentComplexityAnalyzer();
    experimentMetrics = experimentAnalyzer.analyzeFile(options.experimentFile);
  }

  // Calculate complexity score
  const calculator = new ComplexityMetricsCalculator();
  const complexityScore = calculator.calculateOverallScore(apiMetrics, experimentMetrics);

  // Generate optimizations
  const optimizationEngine = new OptimizationEngine();
  const optimizations = optimizationEngine.analyze({
    apiMetrics,
    experimentMetrics
  });

  // Analyze performance impact
  const performanceAnalyzer = new PerformanceImpactAnalyzer();
  const performanceImpact = performanceAnalyzer.analyze(apiMetrics, experimentMetrics);

  // Create report
  const report: ComplexityReport = {
    timestamp: new Date(),
    version: process.env.npm_package_version || '1.0.0',
    apiMetrics,
    experimentMetrics,
    complexityScore,
    optimizations
  };

  // Generate formatted output
  if (options.format) {
    const generator = new ComplexityReportGenerator();
    const output = generator.generate(report, {
      format: options.format,
      includeOptimizations: true
    });

    if (options.outputPath) {
      const { writeFileSync } = await import('fs');
      writeFileSync(options.outputPath, output);
    } else {
      console.log(output);
    }
  }

  return report;
}

