if (!existsSync(experimentFile)) {
  console.error(`❌ File not found: ${experimentFile}`);
  process.exit(1);
}

console.log(`🔍 Analyzing experiment: ${experimentFile}\n`);

try {
  // Read experiment file
  const code = readFileSync(experimentFile, 'utf-8');

  // Analyze experiment complexity
  const analyzer = new ExperimentComplexityAnalyzer();
  const experimentMetrics = analyzer.analyzeExperiment(code, experimentFile);

  // Calculate complexity score (without API metrics for standalone analysis)
  const calculator = new ComplexityMetricsCalculator();
  const apiMetrics = {
    totalExports: 0,
    publicMethods: 0,
    publicClasses: 0,
    publicInterfaces: 0,
    builderMethods: 0,
    deprecatedAPIs: 0,
    complexityScore: 0,
    recommendations: [],
    warnings: [],
    duplicatePatterns: []
  };
  const complexityScore = calculator.calculateOverallScore(apiMetrics, experimentMetrics);

  // Analyze performance impact
  const performanceAnalyzer = new PerformanceImpactAnalyzer();
  const performanceImpact = performanceAnalyzer.analyze(apiMetrics, experimentMetrics);

  // Generate report
  const reportGenerator = new ComplexityReportGenerator();
  const report = {
    timestamp: new Date(),
