    complexityScore,
    performanceImpact
  };

  const output = reportGenerator.generate(report, { 
    format: outputFormat as any,
    includeOptimizations: true
  });

  // Output report
  const outputArg = args.find((arg, i) => args[i - 1] === '--output');
  if (outputArg) {
    const outputDir = dirname(outputArg);
    if (!existsSync(outputDir)) {
      mkdirSync(outputDir, { recursive: true });
    }
    writeFileSync(outputArg, output);
    console.log(`✅ Report saved to: ${outputArg}`);
  } else {
    console.log(output);
  }

  // Exit with appropriate code based on risk level
  if (performanceImpact.overallRisk === 'critical') {
    console.error('\n❌ Critical performance risks detected!');
    process.exit(2);
  } else if (performanceImpact.overallRisk === 'high') {
    console.warn('\n⚠️  High performance risks detected');
