#!/usr/bin/env node

/**
 * Generate optimization suggestions for ForgeScript code
 */

import { ExperimentComplexityAnalyzer } from '../src/api/governance/ExperimentComplexityAnalyzer.js';
import { APILinter } from '../src/api/governance/APILinter.js';
import { OptimizationEngine } from '../src/api/governance/OptimizationEngine.js';
import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));

// Parse command line arguments
const args = process.argv.slice(2);
const targetFile = args[0];
const isAPI = args.includes('--api');
const outputPath = args.find((arg, i) => args[i - 1] === '--output');
const focusAreas = args
  .filter(arg => ['--performance', '--readability', '--maintainability'].includes(arg))
  .map(arg => arg.slice(2)) as ('performance' | 'readability' | 'maintainability')[];

if (!targetFile) {
  console.error(`
Usage: npm run api:optimize <file> [options]

Options:
  --api              Analyze as API file (default: experiment file)
  --performance      Focus on performance optimizations
  --readability      Focus on readability improvements
  --maintainability  Focus on maintainability
  --output <path>    Save suggestions to file

Example:
  npm run api:optimize examples/stroop-task.ts --performance --output optimizations.md
  npm run api:optimize src/index.ts --api --maintainability
`);
  process.exit(1);
}

// Check if file exists
if (!existsSync(targetFile)) {
  console.error(`❌ File not found: ${targetFile}`);
  process.exit(1);
}

console.log(`🚀 Generating optimization suggestions for: ${targetFile}\n`);

try {
  const code = readFileSync(targetFile, 'utf-8');
  const optimizationEngine = new OptimizationEngine();

  let context;

  if (isAPI) {
    // Analyze as API file
    const linter = new APILinter();
    const apiMetrics = linter.analyzeFile(targetFile);
    context = { apiMetrics, focusAreas };
    console.log('📦 Analyzing API complexity...\n');
  } else {
    // Analyze as experiment file
    const analyzer = new ExperimentComplexityAnalyzer();
    const experimentMetrics = analyzer.analyzeExperiment(code, targetFile);
    context = { experimentMetrics, focusAreas };
    console.log('🧪 Analyzing experiment complexity...\n');
  }

  // Generate optimizations
  const suggestions = optimizationEngine.analyze(context);

  if (suggestions.length === 0) {
    console.log('✅ No optimization suggestions - code is well-optimized!');
    process.exit(0);
  }

  // Generate report
  const report = optimizationEngine.generateReport(suggestions);

  // Output suggestions
  if (outputPath) {
    const outputDir = dirname(outputPath);
    if (!existsSync(outputDir)) {
      mkdirSync(outputDir, { recursive: true });
    }
    writeFileSync(outputPath, report);
    console.log(`✅ Suggestions saved to: ${outputPath}`);
  } else {
    console.log(report);
  }

  // Summary
  const highPriority = suggestions.filter(s => s.priority >= 8).length;
  const automatable = suggestions.filter(s => s.automatable).length;

  console.log('\n📊 Summary:');
  console.log(`- Total suggestions: ${suggestions.length}`);
  console.log(`- High priority: ${highPriority}`);
  console.log(`- Automatable: ${automatable}`);

  if (focusAreas.length > 0) {
    console.log(`- Focus areas: ${focusAreas.join(', ')}`);
  }

  // Exit with code based on priority
  if (highPriority > 0) {
    console.warn('\n⚠️  High priority optimizations recommended');
    process.exit(1);
  } else {
    process.exit(0);
  }

} catch (error) {
  console.error('❌ Error generating optimizations:', error);
  process.exit(1);
}

